void AMyPlayerController::BeginPlay() {
    Super::BeginPlay();
    if (UEnhancedInputLocalPlayerSubsystem* Subsystem = 
        ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer())) {
        Subsystem->AddMappingContext(DefaultMappingContext, 0);
    }
}

void AMyCharacter::SetupPlayerInputComponent(UInputComponent* PlayerInputComponent) {
    if (UEnhancedInputComponent* EIC = Cast<UEnhancedInputComponent>(PlayerInputComponent)) {
        EIC->BindAction(MoveAction, ETriggerEvent::Triggered, this, &AMyCharacter::Move);
    }
}

// Opening a menu - allow both game and UI input
void AMyPlayerController::OpenMenu() {
    MenuWidget->SetVisibility(ESlateVisibility::Visible);
    FInputModeGameAndUI InputMode;
    InputMode.SetWidgetToFocus(MenuWidget->TakeWidget());
    InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
    SetInputMode(InputMode);
    SetShowMouseCursor(true);
}

// Closing - restore game input
void AMyPlayerController::CloseMenu() {
    MenuWidget->SetVisibility(ESlateVisibility::Collapsed);
    SetInputMode(FInputModeGameOnly());
    SetShowMouseCursor(false);
}

void AMyCharacter::SetupPlayerInputComponent(UInputComponent* PIC) {
    // This only runs for the locally controlled character
    Super::SetupPlayerInputComponent(PIC);
    // Bind input here - safe because SetupPlayerInputComponent
    // is only called on the locally controlled pawn
}

